return [{ json: {
  quarter: 'Q3 2026',
  last_quarter_summary: {
    shipped: ['SSO (SAML 2.0)', 'Bulk CSV export', 'Recurring tasks (partial — deletion behavior deferred)', 'Mobile app beta (iOS)'],
    missed: ['RBAC (slipped to Q3)', 'Gantt chart view (deprioritised)'],
    key_learnings: ['Enterprise features (SSO, export) drove 3 new enterprise logo wins', 'Mobile app stickier than expected — 45% of beta users active daily', 'RBAC underestimated — needs 6 engineer-weeks, not 3'],
    metrics: { arr_end_of_quarter: 1200000, net_new_arr: 180000, churn_pct: 2.1, nps: 42 }
  },
  proposed_themes_q3: [
    { theme: 'Enterprise security', initiatives: ['RBAC (carry-over)', 'Audit log', 'Data retention policy'], rationale: 'Enterprise deals blocked on security checklist' },
    { theme: 'Mobile GA', initiatives: ['iOS GA from beta', 'Android v1', 'Offline mode'], rationale: 'Mobile stickiness signal — invest to capture retention advantage' },
    { theme: 'Integrations', initiatives: ['Microsoft Teams', 'Salesforce', 'Zapier connector'], rationale: 'Mid-market deals asking for these integrations' }
  ],
  constraints: {
    headcount: '8 engineers, 1 designer, 1 data engineer',
    budget_restriction: 'No new infrastructure spend without VP approval',
    hard_deadlines: ['SOC 2 audit: 2026-09-01 (RBAC and audit log must be done first)']
  },
  strategic_context: 'We are executing a mid-market expansion. Enterprise is strategic but secondary. CompetitorX just raised Series C and is moving upmarket — we have 6-12 months before they compete directly in our core segment.'
} }];

const d = $input.first().json;
const system = `You are a senior PM helping a product team structure their quarterly planning. You produce clear, prioritised recommendations. You flag tradeoffs explicitly. You do not pad. Return ONLY valid JSON.`;
const lastQ = d.last_quarter_summary;
const themes = d.proposed_themes_q3.map(t =>
  `Theme: ${t.theme}\n  Initiatives: ${t.initiatives.join(', ')}\n  Rationale: ${t.rationale}`
).join('\n\n');
const user = `Help me plan ${d.quarter}.

Last quarter:
Shipped: ${lastQ.shipped.join(', ')}
Missed: ${lastQ.missed.join(', ')}
Learnings: ${lastQ.key_learnings.join(' | ')}
Metrics: ARR $${(lastQ.metrics.arr_end_of_quarter/1000).toFixed(0)}k | New ARR $${(lastQ.metrics.net_new_arr/1000).toFixed(0)}k | Churn ${lastQ.metrics.churn_pct}% | NPS ${lastQ.metrics.nps}

Strategic context: ${d.strategic_context}

Proposed themes for ${d.quarter}:
${themes}

Constraints: ${JSON.stringify(d.constraints)}

Return JSON:
{
  "planning_brief_title": "string",
  "recommended_bets": [
    { "theme": "string", "recommended_initiatives": ["string"], "rationale": "string", "estimated_capacity_pct": 40, "confidence": "high|medium|low" }
  ],
  "tradeoffs": ["string — what we are giving up and why it is acceptable"],
  "must_do_this_quarter": ["string — non-negotiable items"],
  "suggested_deferral": ["string — proposed initiatives to drop or defer"],
  "capacity_allocation": { "description": "string", "breakdown": [{ "area": "string", "pct": 40 }] },
  "key_risks": [{ "risk": "string", "mitigation": "string", "severity": "high|medium|low" }],
  "recommended_okrs": [{ "objective": "string", "key_results": ["string"] }]
}`;
return [{ json: { data: d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Planning Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.recommended_bets || !Array.isArray(parsed.recommended_bets)) return [{ json: { _error: true, reason: 'Missing recommended_bets' } }];
return [{ json: { _error: false, brief: parsed, meta: { quarter: upstream.data.quarter, generated_at: new Date().toISOString() } } }];
